import{_ as r,o as a,c as l,ae as e}from"./chunks/framework.DD8idMxO.js";const k=JSON.parse('{"title":"SkillsBench","description":"","frontmatter":{},"headers":[],"relativePath":"radar/tech-skillsbench.md","filePath":"radar/tech-skillsbench.md"}'),i={name:"radar/tech-skillsbench.md"};function o(n,t,s,h,d,c){return a(),l("div",null,[...t[0]||(t[0]=[e('<h1 id="skillsbench" tabindex="-1">SkillsBench <a class="header-anchor" href="#skillsbench" aria-label="Permalink to &quot;SkillsBench&quot;">​</a></h1><blockquote><p><strong>分类</strong>: Skill 评测 | <strong>成熟度</strong>: 🟢 成熟期 | <strong>综合评分</strong>: 0.66</p></blockquote><hr><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><p><strong>一句话描述</strong>: 第一个把 <strong>Skill 本身</strong>作为评测对象的标准化基准 —— 7,308 条轨迹 / 84 任务 / 11 领域，揭示&quot;加 Skill 反而更差&quot;等反共识结论。</p><p><strong>来源</strong>:</p><ul><li>学术研究</li></ul><p><strong>链接</strong>:</p><ul><li>论文：<a href="https://arxiv.org/abs/2602.12670" target="_blank" rel="noreferrer">arXiv 2602.12670</a></li><li>GitHub：<a href="https://github.com/benchflow-ai/skillsbench" target="_blank" rel="noreferrer">benchflow-ai/skillsbench</a></li><li>官网：<a href="https://www.skillsbench.ai/" target="_blank" rel="noreferrer">skillsbench.ai</a></li></ul><hr><h2 id="核心技术" tabindex="-1">核心技术 <a class="header-anchor" href="#核心技术" aria-label="Permalink to &quot;核心技术&quot;">​</a></h2><h3 id="三条件对比设计" tabindex="-1">三条件对比设计 <a class="header-anchor" href="#三条件对比设计" aria-label="Permalink to &quot;三条件对比设计&quot;">​</a></h3><p>同一任务在三种条件下跑 —— 像药物试验的安慰剂对照组：</p><ol><li>不用 Skill</li><li>用精心编写的 Skill</li><li>用 Agent 自己生成的 Skill</li></ol><h3 id="关键发现-不是解决方案-是问题揭示" tabindex="-1">关键发现（不是解决方案，是问题揭示） <a class="header-anchor" href="#关键发现-不是解决方案-是问题揭示" aria-label="Permalink to &quot;关键发现（不是解决方案，是问题揭示）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>发现</th><th>数据</th></tr></thead><tbody><tr><td><strong>精心编写的 Skill 显著有效</strong></td><td>平均提升 +16.2pp</td></tr><tr><td><strong>但领域差异巨大</strong></td><td>软件工程仅 +4.5pp，医疗 +51.9pp（差了 10×）</td></tr><tr><td><strong>自生成 Skill 平均无增益</strong></td><td>学生自己写复习笔记帮不了自己</td></tr><tr><td><strong>部分场景 Skill 有害</strong></td><td>84 任务中 <strong>16 个负增益</strong> —— 加了反而更差</td></tr><tr><td><strong>聚焦优于全面</strong></td><td>2-3 模块精简 Skill 优于长篇文档</td></tr></tbody></table><h3 id="关键意义" tabindex="-1">关键意义 <a class="header-anchor" href="#关键意义" aria-label="Permalink to &quot;关键意义&quot;">​</a></h3><p>SkillsBench 不解决问题，但<strong>第一次量化</strong>了 Skill 生态中最重要的几个反共识事实，是后续所有评测和优化工作的起点。</p><hr><h2 id="技术细节" tabindex="-1">技术细节 <a class="header-anchor" href="#技术细节" aria-label="Permalink to &quot;技术细节&quot;">​</a></h2><h3 id="局限性" tabindex="-1">局限性 <a class="header-anchor" href="#局限性" aria-label="Permalink to &quot;局限性&quot;">​</a></h3><ul><li>只做 <strong>pass/fail 结果评测</strong>，<strong>不追踪 Agent 是否实际遵从了 Skill 流程</strong></li><li>无法解释 16 个负增益案例的根因（&quot;Agent 忽略了 Skill？Skill 有缺陷？路由选错？&quot;）</li><li>84 个确定性验证器都是手工编写的，覆盖 11 个领域 —— 但 SkillNet 上有 200K+ Skill 横跨数百领域，绝大多数没有评测基础设施</li></ul><hr><h2 id="成熟度评分" tabindex="-1">成熟度评分 <a class="header-anchor" href="#成熟度评分" aria-label="Permalink to &quot;成熟度评分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>评分</th><th>说明</th></tr></thead><tbody><tr><td>技术成熟度</td><td>0.75</td><td>已成事实标准</td></tr><tr><td>创新性</td><td>0.65</td><td>设计严谨，结论开创</td></tr><tr><td>落地程度</td><td>0.65</td><td>多个后续工作引用为基线</td></tr><tr><td>生态活跃度</td><td>0.55</td><td>活跃</td></tr></tbody></table><p><strong>综合评分</strong>: <strong>0.66</strong></p><hr><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2602.12670" target="_blank" rel="noreferrer">SkillsBench 论文</a></li><li><a href="https://github.com/benchflow-ai/skillsbench" target="_blank" rel="noreferrer">GitHub</a></li><li><a href="https://www.skillsbench.ai/" target="_blank" rel="noreferrer">官网</a></li></ul>',29)])])}const g=r(i,[["render",o]]);export{k as __pageData,g as default};
